class Solution {
    public int maxConsecutiveAnswers(String answerKey, int k) {
        return Math.max(maxConsecutiveCount(answerKey, k, 'T'), maxConsecutiveCount(answerKey, k, 'F'));
    }

    private int maxConsecutiveCount(String answerKey, int k, char target) {
        int left = 0;
        int maxCount = 0;
        int count = 0;

        for (int right = 0; right < answerKey.length(); right++) {
            if (answerKey.charAt(right) != target) {
                count++;
            }

            while (count > k) {
                if (answerKey.charAt(left) != target) {
                    count--;
                }
                left++;
            }

            maxCount = Math.max(maxCount, right - left + 1);
        }

        return maxCount;
    }
}
